// 두 소스(점프잇/원티드)의 목록 응답을 공통 스키마로 정규화한다.
// 입력: Merge 노드가 합친 목록 응답 아이템들.
//   - 점프잇 응답: json.result.positions[]
//   - 원티드 응답: json.positions.data[] (또는 json.data[])
// 출력: 공고 1건당 아이템 1개.
// 주의: 비공식 API라 필드명이 바뀔 수 있음 -> 첫 실행 후 실제 응답을 보고 매핑 조정.

const stripTags = (s) => (s || '').replace(/<[^>]*>/g, '').trim();
const out = [];
const allowed = $('설정 (Config)').first().json.allowedWantedCategories || [518, 507];  // 원티드 허용 직군(화이트리스트)

for (const item of $input.all()) {
  const j = item.json || {};

  // ---- 점프잇 ----
  const jumpit = j.result?.positions;
  if (Array.isArray(jumpit)) {
    for (const p of jumpit) {
      out.push({ json: {
        source: 'jumpit',
        jobId: String(p.id ?? ''),
        company: p.companyName ?? p.company ?? '',
        title: stripTags(p.title),            // <span> 하이라이트 태그 제거
        url: `https://jumpit.saramin.co.kr/position/${p.id}`,
        minCareer: p.minCareer ?? null,
        maxCareer: p.maxCareer ?? null,
        techStacks: (p.techStacks || []).map(t => stripTags(typeof t === 'string' ? t : (t.stack ?? t.name ?? ''))),  // <span> 하이라이트 제거
        locations: p.locations ?? (p.jobCity ? [p.jobCity] : []),
        closedAt: p.closedAt ?? null,
      }});
    }
    continue;
  }

  // ---- 원티드 ----
  const wanted = j.positions?.data ?? j.data;
  if (Array.isArray(wanted)) {
    for (const p of wanted) {
      // 직군 화이트리스트: 허용 parent_id만 통과 (분류불가=통과, 목록 비면 필터OFF)
      const pid = p.category_tag?.parent_id;
      if (allowed.length && pid != null && !allowed.includes(pid)) continue;
      out.push({ json: {
        source: 'wanted',
        jobId: String(p.id ?? ''),
        company: p.company?.name ?? p.company_name ?? '',
        title: p.position ?? p.title ?? '',
        url: `https://www.wanted.co.kr/wd/${p.id}`,
        minCareer: p.annual_from ?? null,
        maxCareer: p.annual_to ?? null,
        techStacks: (p.skill_tags || p.tags || []).map(t => typeof t === 'string' ? t : (t.title ?? t.name ?? '')),
        locations: p.address ? [p.address] : (p.location ? [p.location] : []),
        closedAt: p.due_time ?? null,
      }});
    }
    continue;
  }
}

return out;

// 필터 전용: 중복 공고를 제외하고 새 공고만 통과시킨다. 두 가지 중복을 모두 처리:
//  ① 이전 실행에서 요약 성공한 공고 (static data의 seen)
//  ② 이번 실행 내 중복 (여러 키워드에 걸린 같은 공고 — OR 검색이라 생김)
// seen 기록(성공분)은 'Markdown 생성'에서 수행한다.
const staticData = $getWorkflowStaticData('global');
const seen = staticData.seenJobIds || {};
const seenThisRun = new Set();

const fresh = [];
for (const item of $input.all()) {
  const key = `${item.json.source}:${item.json.jobId}`;
  if (seen[key] || seenThisRun.has(key)) continue;   // 이전 실행 or 이번 실행 내 중복 제외
  seenThisRun.add(key);
  fresh.push(item);
}
return fresh;

// 상세(JD) 응답을 파싱해 LLM 프롬프트를 만들고, 연차 상한으로 필터링한다.
// [All Items 모드] 상세조회 결과($input)와 Dedup 메타를 인덱스로 짝짓는다.
// (Each Item 모드에서는 return []로 항목을 못 버려서 All Items로 처리)

const metas   = $('중복 제거 (Dedup)').all();   // 정규화 메타 (인덱스 정렬)
const details = $input.all();                   // 상세 API 응답 (인덱스 정렬)
const maxYears = Number($('설정 (Config)').first().json.maxCareerYears);

const out = [];
for (let i = 0; i < details.length; i++) {
  const meta = metas[i]?.json || {};
  const d = details[i]?.json || {};

  let responsibility = '', qualifications = '', preferred = '';
  if (d.result) {                       // 점프잇 상세
    responsibility = d.result.responsibility || '';
    qualifications = d.result.qualifications || '';
    preferred      = d.result.preferredRequirements || '';
  } else if (d.data?.job?.detail) {     // 원티드 상세
    const det = d.data.job.detail;
    responsibility = det.main_tasks || det.intro || '';
    qualifications = det.requirements || '';
    preferred      = det.preferred_points || '';
  }

  // 연차 보완: 점프잇=목록 minCareer/maxCareer, 원티드=상세 annual_from/to
  let minCareer = meta.minCareer;
  let maxCareer = meta.maxCareer;
  if (d.data?.job) {
    if (minCareer == null) minCareer = d.data.job.annual_from ?? null;
    if (maxCareer == null) maxCareer = d.data.job.annual_to ?? null;
  }
  if (maxCareer != null && maxCareer > 20) maxCareer = null;  // 상한 sentinel(100 등) 정리

  // 연차 필터: 최소 요구 경력 > 상한이면 제외. 신입/무관(null·0) 통과, 상한 미설정 시 OFF
  if (Number.isFinite(maxYears) && minCareer != null && minCareer > maxYears) continue;

  const prompt = `제목: ${meta.title}\n회사: ${meta.company}\n\n[주요업무]\n${responsibility}\n\n[자격요건]\n${qualifications}\n\n[우대사항]\n${preferred}`;
  out.push({ json: { ...meta, minCareer, maxCareer, responsibility, qualifications, preferred, prompt } });
}

return out;

// AI 요약 결과 + 공고 메타데이터를 하나의 Markdown 문서로 합친다.
// 추가로, 요약에 성공한 공고만 seen에 기록해 다음 실행부터 스킵한다(실패는 재시도되도록).
const aiItems = $input.all();
const metaItems = $('AI 입력 준비').all();
const staticData = $getWorkflowStaticData('global');
const seen = staticData.seenJobIds || {};

const today = new Date().toISOString().slice(0, 10);
let md = `# 채용 공고 요약 (${today})\n\n총 ${aiItems.length}건\n\n`;

for (let i = 0; i < aiItems.length; i++) {
  const meta = metaItems[i]?.json || {};
  const rawContent = aiItems[i]?.json?.choices?.[0]?.message?.content;
  const summary = rawContent || '(요약 실패 - LM Studio 응답 확인 필요)';
  const career = [meta.minCareer, meta.maxCareer]
    .filter(v => v !== null && v !== undefined).join('~') || '무관';
  // 점프잇은 구조화 techStacks, 원티드는 AI 요약의 '기술스택:' 라인에서 추출
  let stacks = (meta.techStacks || []).join(', ');
  if (!stacks) {
    const m = summary.match(/기술스택\s*[:：]\s*(.+)/);
    if (m) { const v = m[1].trim(); if (v && v !== '-') stacks = v; }
  }
  stacks = stacks || '-';

  md += `## ${meta.title} — ${meta.company}\n\n`;
  md += `- 링크: ${meta.url}\n`;
  md += `- 경력: ${career}\n`;
  md += `- 기술스택: ${stacks}\n`;
  md += `- 출처: ${meta.source}\n\n`;
  md += `### AI 요약\n${summary}\n\n---\n\n`;

  // 요약 성공 시에만 seen 기록 (rawContent가 있으면 성공)
  if (rawContent && meta.source && meta.jobId) {
    seen[`${meta.source}:${meta.jobId}`] = Date.now();
  }
}

staticData.seenJobIds = seen;   // 성공한 공고만 다음 실행부터 스킵

const binary = await this.helpers.prepareBinaryData(
  Buffer.from(md, 'utf-8'), 'jobs-summary.md', 'text/markdown');

return [{ json: { markdown: md, count: aiItems.length }, binary: { data: binary } }];

// 디스코드로 보낼 것: 공고별 '클릭 가능한 임베드 카드'. 임베드 10개씩 묶어 메시지 구성.
const metaItems = $('AI 입력 준비').all();
const aiItems   = $('AI 요약 (LM Studio)').all();
const webhook   = $('설정 (Config)').first().json.discordWebhookUrl || '';

if (!webhook || metaItems.length === 0) return [];

const today = new Date().toISOString().slice(0, 10);

// ① 공고별 임베드 생성
const embeds = [];
for (let i = 0; i < metaItems.length; i++) {
  const m = metaItems[i].json;
  const content = aiItems[i]?.json?.choices?.[0]?.message?.content || '';

  // 설명: 요약 본문에서 '기술스택:' 라인은 제거(카드 필드에 따로 넣으므로 중복 방지)
  let desc = content.replace(/\n?기술스택\s*[:：].*$/m, '').trim();
  if (desc.length > 400) desc = desc.slice(0, 400) + '…';

  // 기술스택: 점프잇=구조화, 원티드=요약에서 추출
  let stacks = (m.techStacks || []).join(', ');
  if (!stacks) { const mm = content.match(/기술스택\s*[:：]\s*(.+)/); if (mm) stacks = mm[1].trim(); }

  const career = [m.minCareer, m.maxCareer].filter(v => v != null).join('~') || '무관';

  embeds.push({
    title: `${m.company} — ${m.title}`.slice(0, 250),
    url: m.url,
    color: 5814783,
    description: desc || '(요약 없음)',
    fields: [
      { name: '경력', value: String(career), inline: true },
      { name: '기술스택', value: (stacks || '-').slice(0, 1000), inline: true },
      { name: '출처', value: String(m.source), inline: true },
    ],
  });
}

// ② 임베드 10개씩 묶어 메시지로 (첫 메시지에 헤더 content)
const out = [];
for (let i = 0; i < embeds.length; i += 10) {
  const item = { embeds: embeds.slice(i, i + 10) };
  if (i === 0) item.content = `📋 **오늘의 채용 공고 ${embeds.length}건** (${today})`;
  out.push({ json: item });
}
return out;
